   392| * @param {Object} [options]
   393| * @param {boolean} [options.dryRun=false]
   394| * @param {boolean} [options.stopOnWaveFailure=false]
   395| * @param {(result: WaveResult) => void} [options.onWaveComplete]
   396| * @returns {Promise<{meta: import('./parser.js').TaskMeta, waveResults: WaveResult[]}>}
   397| */
   398|export async function executePlan(planPath, options = {}) {
